#[derive(Debug, Clone, PartialEq, Eq)]
pub enum CommandResolution {
    Builtin {
        name: &'static str,
    },
    SovereignAlias {
        command: &'static str,
        target: &'static str,
        prepended_args: &'static [&'static str],
    },
    GuardedHost {
        command: String,
        caps: &'static [&'static str],
        reason: &'static str,
    },
    PlatformAlias {
        command: &'static str,
        platform: &'static str,
        portable: &'static str,
    },
    Missing {
        command: String,
    },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScheduledCommandRow {
    pub command: &'static str,
    pub resolution: CommandResolution,
    pub light: Stoplight,
    pub chamber: Chirality,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdmissionRow {
    pub name: String,
    pub kind: String,
    pub path: String,
    pub caps: Vec<String>,
    pub build: String,
    pub quality: Option<String>,
    pub oath: Option<String>,
}

